import{_ as t,o as n,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"65. Reasonable Adjustments","description":"","frontmatter":{"title":"65. Reasonable Adjustments","eba":"Allied Health Professionals 2021-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/allied-health/leave/65-reasonable-adjustments.md","filePath":"ebas/allied-health/leave/65-reasonable-adjustments.md"}'),a={name:"ebas/allied-health/leave/65-reasonable-adjustments.md"};function r(i,e,l,d,p,m){return n(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_65-reasonable-adjustments" tabindex="-1">65. Reasonable Adjustments <a class="header-anchor" href="#_65-reasonable-adjustments" aria-label="Permalink to &quot;65. Reasonable Adjustments&quot;">​</a></h1><p><strong>65.1</strong> Where an Employee has a Disability (whether permanent or temporary) the Employer is required to make Reasonable Adjustments to enable the Employee to continue to perform their duties, subject to subclause 65.2 below.</p><p><strong>65.2</strong> An Employer is not required to make Reasonable Adjustments if the Employee could not or cannot adequately perform the genuine and reasonable requirements of the employment even after the Reasonable Adjustments are made.</p><p><strong>65.3</strong> Definitions</p><p><strong>(a)</strong> Disability has the same meaning as section 4 of the EO Act and includes:</p><p><strong>(i)</strong> total or partial loss of a bodily function;</p><p><strong>(ii)</strong> presence in the body of organisms that may cause disease;</p><p><strong>(iii)</strong> total or partial loss of a part of the body; or</p><p><strong>(iv)</strong> malfunction of a part of the body including a mental or psychological disease or disorder or condition or disorder that results in a person learning more slowly than those without the condition or disorder.</p><p><strong>(b)</strong> Reasonable Adjustments has the same meaning as section 20 of the EO Act and requires consideration of all relevant facts and circumstances including:</p><p><strong>(i)</strong> the Employee’s circumstances, including the nature of the Disability;</p><p><strong>(ii)</strong> the nature of the Employee’s role;</p><p><strong>(iii)</strong> the nature of the adjustment required to accommodate the Employee’s disability;</p><p><strong>(iv)</strong> the financial circumstances of the Employer;</p><p><strong>(v)</strong> the size and nature of the workplace and the Employer’s business;</p><p><strong>(vi)</strong> the effect on the workplace and the Employer’s business of making the adjustment including the financial impact, the number of persons who would benefit or be disadvantaged and the impact of efficiency and productivity;</p><p><strong>(vii)</strong> the consequences for the Employer in making the adjustment; and</p><p><strong>(viii)</strong> the consequences for the Employee in not making the adjustment.</p>',18)])])}const u=t(a,[["render",r]]);export{c as __pageData,u as default};
